                CUBLAS_OP_N, CUBLAS_OP_N,
                d, d, d,
                &alpha,
                X.data_ptr<float>(), d,
                W.data_ptr<float>(), d,
                &beta0,
                Y.data_ptr<float>(), d);

    // U_col[d,16] = X_col * B_col^T
    cublasSgemm(handle,
                CUBLAS_OP_N, CUBLAS_OP_T,
                d, 16, d,
                &alpha,
                X.data_ptr<float>(), d,
                B.data_ptr<float>(), 16,
                &beta0,
                U.data_ptr<float>(), d);

    // Y_col += U_col * A_col
